// ─── Procesar GA4 Landing Pages ───────────────────────────────────────────
const ga4Response = $input.first().json;
const vars = $('Set Variables').first().json;

const dimensionHeaders = ga4Response.dimensionHeaders || [];
const metricHeaders    = ga4Response.metricHeaders   || [];
const rows             = ga4Response.rows             || [];

// Mapear índices
const dimIdx = {};
dimensionHeaders.forEach((h, i) => { dimIdx[h.name] = i; });
const metIdx = {};
metricHeaders.forEach((h, i) => { metIdx[h.name] = i; });

// Parsear cada fila
const landingRows = rows.map(row => {
  const d = row.dimensionValues || [];
  const m = row.metricValues    || [];

  const sessions        = parseFloat(m[metIdx['sessions']]?.value        || '0');
  const purchases       = parseFloat(m[metIdx['purchases']]?.value       || '0');
  const revenue         = parseFloat(m[metIdx['purchaseRevenue']]?.value  || '0');
  const engagedSessions = parseFloat(m[metIdx['engagedSessions']]?.value || '0');
  const engagementRate  = parseFloat(m[metIdx['engagementRate']]?.value  || '0');
  const addToCarts      = parseFloat(m[metIdx['addToCarts']]?.value      || '0');
  const conversionRate  = parseFloat(m[metIdx['sessionConversionRate']]?.value || '0');

  return {
    date:             vars.dateYesterday,
    landingPage:      d[dimIdx['landingPage']]?.value      || '(not set)',
    channel:          d[dimIdx['sessionDefaultChannelGroup']]?.value || '(not set)',
    campaign:         d[dimIdx['sessionCampaign']]?.value  || '(not set)',
    device:           d[dimIdx['deviceCategory']]?.value   || '(not set)',
    sessions,
    engagedSessions,
    engagementRate:   Math.round(engagementRate * 10000) / 10000,
    purchases,
    revenue:          Math.round(revenue * 100) / 100,
    addToCarts,
    conversionRate:   Math.round(conversionRate * 10000) / 10000,
    revenuePerSession: sessions > 0 ? Math.round((revenue / sessions) * 100) / 100 : 0
  };
});

// Calcular totales globales
const totalSessions   = landingRows.reduce((s, r) => s + r.sessions,  0);
const totalPurchases  = landingRows.reduce((s, r) => s + r.purchases, 0);
const totalRevenue    = Math.round(landingRows.reduce((s, r) => s + r.revenue, 0) * 100) / 100;
const avgConversionRate = totalSessions > 0
  ? Math.round((totalPurchases / totalSessions) * 10000) / 10000
  : 0;

// Top landings
const byRevenue  = [...landingRows].sort((a, b) => b.revenue  - a.revenue);
const bySessions = [...landingRows].sort((a, b) => b.sessions - a.sessions);

// Top channel (basado en revenue)
const channelRevenue = {};
landingRows.forEach(r => {
  channelRevenue[r.channel] = (channelRevenue[r.channel] || 0) + r.revenue;
});
const topChannel = Object.entries(channelRevenue)
  .sort((a, b) => b[1] - a[1])[0]?.[0] || '(not set)';

const summary = {
  date:                 vars.dateYesterday,
  totalSessions,
  totalPurchases,
  totalRevenue,
  avgConversionRate,
  topLandingByRevenue:  byRevenue[0]?.landingPage  || '(none)',
  topLandingBySessions: bySessions[0]?.landingPage || '(none)',
  topChannel,
  // Top 3 landings para el mensaje de Teams
  top3Landings: byRevenue.slice(0, 3).map(r => ({
    landingPage:    r.landingPage,
    revenue:        r.revenue,
    conversionRate: r.conversionRate,
    sessions:       r.sessions
  }))
};

return [
  {
    json: {
      landingRows,
      summary
    }
  }
];

// ─── Procesar GA4 Canales ─────────────────────────────────────────────────
const ga4Response = $input.first().json;

const dimensionHeaders = ga4Response.dimensionHeaders || [];
const metricHeaders    = ga4Response.metricHeaders   || [];
const rows             = ga4Response.rows             || [];

const dimIdx = {};
dimensionHeaders.forEach((h, i) => { dimIdx[h.name] = i; });
const metIdx = {};
metricHeaders.forEach((h, i) => { metIdx[h.name] = i; });

// Mapeo de grupos de canal GA4 → categorías propias
const channelMap = {
  'Organic Search':  'organic',
  'Direct':          'direct',
  'Paid Search':     'paid',
  'Paid Social':     'paid',
  'Display':         'paid',
  'Email':           'email',
  'Organic Social':  'social',
  'Referral':        'other',
  'Affiliates':      'other',
  '(Other)':         'other',
  'Unassigned':      'other'
};

const channels = {
  organic: { sessions: 0, purchases: 0, revenue: 0, convRate: 0 },
  paid:    { sessions: 0, purchases: 0, revenue: 0, convRate: 0 },
  email:   { sessions: 0, purchases: 0, revenue: 0, convRate: 0 },
  direct:  { sessions: 0, purchases: 0, revenue: 0, convRate: 0 },
  social:  { sessions: 0, purchases: 0, revenue: 0, convRate: 0 },
  other:   { sessions: 0, purchases: 0, revenue: 0, convRate: 0 }
};

rows.forEach(row => {
  const d = row.dimensionValues || [];
  const m = row.metricValues   || [];

  const ga4Channel = d[dimIdx['sessionDefaultChannelGroup']]?.value || '(Other)';
  const key        = channelMap[ga4Channel] || 'other';

  const sessions  = parseFloat(m[metIdx['sessions']]?.value         || '0');
  const purchases = parseFloat(m[metIdx['purchases']]?.value        || '0');
  const revenue   = parseFloat(m[metIdx['purchaseRevenue']]?.value   || '0');
  const convRate  = parseFloat(m[metIdx['sessionConversionRate']]?.value || '0');

  channels[key].sessions  += sessions;
  channels[key].purchases += purchases;
  channels[key].revenue   += revenue;
  // Promedio ponderado de tasa de conversión
  if (channels[key].sessions > 0) {
    channels[key].convRate =
      Math.round((channels[key].purchases / channels[key].sessions) * 10000) / 10000;
  }
});

// Redondear revenue
Object.keys(channels).forEach(k => {
  channels[k].revenue = Math.round(channels[k].revenue * 100) / 100;
});

return [{ json: { channels } }];

// ─── Validación VTEX vs GA4 ───────────────────────────────────────────────
const vtexResponse = $input.first().json;
const ga4Data      = $('Procesar GA4 Landing Pages').first().json;

const vtexTotalOrders = vtexResponse?.paging?.total ?? 0;
const ga4TotalPurchases = ga4Data.summary?.totalPurchases ?? 0;

const diferenciaAbsoluta = vtexTotalOrders - ga4TotalPurchases;
const diferenciaPct = vtexTotalOrders > 0
  ? Math.round(Math.abs((vtexTotalOrders - ga4TotalPurchases) / vtexTotalOrders) * 10000) / 100
  : 0;

let statusValidacion;
if (diferenciaPct < 10) {
  statusValidacion = '✅ OK';
} else if (diferenciaPct <= 20) {
  statusValidacion = '⚠️ REVISAR';
} else {
  statusValidacion = '🚨 ALERTA';
}

return [
  {
    json: {
      vtexTotalOrders,
      ga4TotalPurchases,
      diferenciaAbsoluta,
      diferenciaPct,
      statusValidacion
    }
  }
];

// ─── Agregar datos semanales para mensaje de Teams ────────────────────────
const weekRows = $input.all().map(item => item.json);
const vars     = $('Set Variables').first().json;

if (!weekRows.length) {
  return [{ json: { weeklyStats: null, weekStart: vars.weekStart, weekEnd: vars.weekEnd } }];
}

const sumRevenue    = weekRows.reduce((s, r) => s + (parseFloat(r.totalRevenue) || 0), 0);
const sumPurchases  = weekRows.reduce((s, r) => s + (parseFloat(r.totalPurchases) || 0), 0);
const sumSessions   = weekRows.reduce((s, r) => s + (parseFloat(r.totalSessions) || 0), 0);
const avgConversion = sumSessions > 0
  ? Math.round((sumPurchases / sumSessions) * 10000) / 100
  : 0;

// Revenue por canal acumulado
const organicRevTotal = weekRows.reduce((s, r) => s + (parseFloat(r.organic_revenue) || 0), 0);
const paidRevTotal    = weekRows.reduce((s, r) => s + (parseFloat(r.paid_revenue)    || 0), 0);
const emailRevTotal   = weekRows.reduce((s, r) => s + (parseFloat(r.email_revenue)   || 0), 0);
const directRevTotal  = weekRows.reduce((s, r) => s + (parseFloat(r.direct_revenue)  || 0), 0);

const totalRevForPct = sumRevenue || 1;
const organicPct = Math.round((organicRevTotal / totalRevForPct) * 10000) / 100;
const paidPct    = Math.round((paidRevTotal    / totalRevForPct) * 10000) / 100;
const emailPct   = Math.round((emailRevTotal   / totalRevForPct) * 10000) / 100;
const directPct  = Math.round((directRevTotal  / totalRevForPct) * 10000) / 100;

// Top 3 landings de la semana (agrupado por landingPage)
const landingMap = {};
weekRows.forEach(r => {
  const key = r.topLandingByRevenue || '(none)';
  if (!landingMap[key]) landingMap[key] = { landingPage: key, revenue: 0, purchases: 0 };
  landingMap[key].revenue   += parseFloat(r.totalRevenue)   || 0;
  landingMap[key].purchases += parseFloat(r.totalPurchases) || 0;
});
const top3 = Object.values(landingMap)
  .sort((a, b) => b.revenue - a.revenue)
  .slice(0, 3);

// Diferencia promedio VTEX vs GA4
const avgDifPct = weekRows.length > 0
  ? Math.round(
      weekRows.reduce((s, r) => s + (parseFloat(r.diferenciaPct) || 0), 0) / weekRows.length * 100
    ) / 100
  : 0;

return [{
  json: {
    weekStart: vars.weekStart,
    weekEnd:   vars.weekEnd,
    sumRevenue:    Math.round(sumRevenue * 100) / 100,
    sumPurchases,
    sumSessions,
    avgConversion,
    organicRevTotal: Math.round(organicRevTotal * 100) / 100,
    paidRevTotal:    Math.round(paidRevTotal * 100) / 100,
    emailRevTotal:   Math.round(emailRevTotal * 100) / 100,
    directRevTotal:  Math.round(directRevTotal * 100) / 100,
    organicPct,
    paidPct,
    emailPct,
    directPct,
    top3,
    avgDifPct
  }
}];

