// ─── Construir payload para mensaje diario de Teams ───────────────────────
const ga4Data    = $('Procesar GA4 Landing Pages').first().json;
const channels   = $('Procesar GA4 Canales').first().json.channels;
const validation = $('Validación VTEX vs GA4').first().json;
const summary    = ga4Data.summary;
const top3       = summary.top3Landings || [];

// Asegurar que hay 3 entradas para el template
while (top3.length < 3) {
  top3.push({ landingPage: '(sin datos)', revenue: 0, conversionRate: 0 });
}

return [{
  json: {
    date:             summary.date,
    totalRevenue:     summary.totalRevenue,
    totalPurchases:   summary.totalPurchases,
    totalSessions:    summary.totalSessions,
    avgConversionRate: Math.round(summary.avgConversionRate * 100 * 100) / 100,
    topChannel:       summary.topChannel,
    paid_rev:         channels.paid.revenue,
    organic_rev:      channels.organic.revenue,
    landing_1:        top3[0].landingPage,
    rev_1:            top3[0].revenue,
    conv_1:           Math.round(top3[0].conversionRate * 100 * 100) / 100,
    landing_2:        top3[1].landingPage,
    rev_2:            top3[1].revenue,
    conv_2:           Math.round(top3[1].conversionRate * 100 * 100) / 100,
    landing_3:        top3[2].landingPage,
    rev_3:            top3[2].revenue,
    conv_3:           Math.round(top3[2].conversionRate * 100 * 100) / 100,
    statusValidacion: validation.statusValidacion,
    vtexOrders:       validation.vtexTotalOrders,
    ga4Purchases:     validation.ga4TotalPurchases
  }
}];

